1. Next, define the page component and the types for the post:
```typescript
// app/blog/[postId]/page.tsx

import React from 'react';

interface Post {
  id: number;
  title: string;
  body: string;
}

interface PageProps {
  post: Post;
}

const Page: React.FC<PageProps> = ({ post }) => {
  return (
    <div>
      <h1>{post.title}</h1>
      <p>{post.body}</p>
    </div>
  );
};

export default Page;
```
1. Now, define the `generateStaticParams` function to fetch the post IDs:
```typescript
// app/blog/[postId]/page.tsx

import type { GenerateStaticParams } from 'next';

interface Params {
  postId: string;
}

export const generateStaticParams: GenerateStaticParams<Params> = async () => {
  const response = await fetch('https://jsonplaceholder.typicode.com/posts');
  const posts = await response.json();

  return posts.map((post: { id: number }) => ({
    postId: post.id.toString(),
  }));
};
```
